    45→function getCardBorderPath(race: Race | null): string {
    46→  if (race === "Orc") return "/buttons/esc/orc/orc-options-menu-border.blp";
    47→  if (race === "NightElf")
    48→    return "/buttons/esc/nightelf/nightelf-options-menu-border.blp";
