    60→    void loadBlpDataUrl(path)
    61→      .then((url) => loadDataUrlImage(url))
    62→      .then((img) => {
    63→        if (cancelled) return;
    64→        setBorderImageUrl(composeBorderImageFromAtlas(img));
    65→      })
    66→      .catch((err) => console.error(err));
    67→    return () => {
    68→      cancelled = true;
    69→    };
    70→  }, [race]);
    71→
    72→  return borderImageUrl;
    73→}
