   114→
   115→  // Sync native scroll → scrollbar percentage
   116→  useEffect(() => {
   117→    const el = tableRef.current;
   118→    if (!el) return;
   119→    const handler = () => {
   120→      if (scrollingFromBar.current) return;
   121→      const maxScroll = el.scrollHeight - el.clientHeight;
   122→      if (maxScroll <= 0) {
   123→        setScrollPct(0);
