   125→      }
   126→      setScrollPct((el.scrollTop / maxScroll) * 100);
   127→    };
   128→    el.addEventListener("scroll", handler, { passive: true });
   129→    return () => el.removeEventListener("scroll", handler);
   130→  }, []);
   131→
