   138→    if (maxScroll <= 0) return;
   139→    scrollingFromBar.current = true;
   140→    el.scrollTop = (pct / 100) * maxScroll;
   141→    requestAnimationFrame(() => {
   142→      scrollingFromBar.current = false;
   143→    });
