   179→                } as React.CSSProperties}
   180→              >
   181→                <HeroPortraitModel race={buildRace} />
   182→              </div>
   183→              <img
   184→                src={`/console/${buildRace}/${RACE_PREFIXES[buildRace].tile}UIPortraitFrameCrop.png`}
   185→                alt=""
