   288→export default function BuildOrdersSection() {
   289→  const running = useTimerRunning();
   290→  const elapsed = useElapsedSeconds();
   291→  const currentRace = useCurrentRace();
   292→  const borderImageUrl = useCardBorderImage(currentRace);
   293→  const allBuilds = useBuildOrders();
   294→
   295→  const relevantBuilds = allBuilds.filter(
   296→    (b) => !currentRace || b.race === currentRace,
   297→  );
   298→
   299→  const [selectedIndex, setSelectedIndex] = useState(0);
   300→  const [importStatus, setImportStatus] = useState("");
   301→  const fileInputRef = useRef<HTMLInputElement>(null);
   302→
   303→  // Reset selection and timer when race changes
   304→  useEffect(() => {
   305→    setSelectedIndex(0);
   306→    resetTimer();
   307→  }, [currentRace]);
   308→
   309→  const selectedBuild =
   310→    relevantBuilds.length > 0
   311→      ? relevantBuilds[Math.min(selectedIndex, relevantBuilds.length - 1)]
   312→      : null;
   313→
   314→  // Build dropdown option keys — use indices as stable identifiers
   315→  const optionKeys = relevantBuilds.map((_, i) => String(i));
   316→
   317→  const handleImport = useCallback(() => {
   318→    fileInputRef.current?.click();
   319→  }, []);
   320→
   321→  const handleFileChange = useCallback(
   322→    (e: React.ChangeEvent<HTMLInputElement>) => {
   323→      const file = e.target.files?.[0];
   324→      if (!file) return;
   325→
   326→      const reader = new FileReader();
   327→      reader.onload = () => {
   328→        try {
   329→          const json = JSON.parse(reader.result as string);
   330→          const count = importBuilds(json);
   331→          if (count > 0) {
   332→            setImportStatus(`Imported ${count} build${count > 1 ? "s" : ""}`);
   333→          } else {
   334→            setImportStatus("No valid builds found in file");
   335→          }
   336→        } catch {
   337→          setImportStatus("Invalid JSON file");
   338→        }
   339→        // Clear so the same file can be re-imported
   340→        e.target.value = "";
   341→        setTimeout(() => setImportStatus(""), 4000);
   342→      };
   343→      reader.readAsText(file);
   344→    },
   345→    [],
   346→  );
   347→
   348→  return (
   349→    <div className="tab-content">
   350→      <section className="section-card build-orders-section">
   351→        <div className="build-orders-toolbar">
   352→          <h3>Build Orders</h3>
   353→          <div className="build-orders-toolbar-actions">
   354→            <div className="build-orders-race-picker">
   355→              <GlueDropdown
   356→                options={RACES}
   357→                value={currentRace}
   358→                onChange={(v) => setCurrentRace(v as Race)}
   359→                label={(v) => RACE_LABELS[v as Race] ?? v}
   360→              />
   361→            </div>
   362→            {relevantBuilds.length > 1 && (
   363→              <GlueDropdown
   364→                options={optionKeys}
   365→                value={String(
   366→                  Math.min(selectedIndex, relevantBuilds.length - 1),
   367→                )}
   368→                onChange={(v) => {
   369→                  setSelectedIndex(Number(v));
   370→                  resetTimer();
   371→                }}
   372→                label={(v) => relevantBuilds[Number(v)]?.name ?? ""}
   373→              />
   374→            )}
   375→            <GlueBorderedButton onClick={handleImport}>Import</GlueBorderedButton>
   376→            <input
   377→              ref={fileInputRef}
   378→              type="file"
   379→              accept=".json"
   380→              className="build-import-input"
   381→              onChange={handleFileChange}
   382→            />
   383→          </div>
   384→        </div>
   385→        {importStatus && (
   386→          <div className="build-import-status">{importStatus}</div>
   387→        )}
   388→
   389→        {!selectedBuild ? (
   390→          <p className="build-card-empty">
   391→            No build orders available for this race.
   392→          </p>
   393→        ) : (
   394→          <>
   395→            <BuildCard
   396→              key={`${currentRace}-${selectedIndex}`}
   397→              build={selectedBuild}
   398→              elapsed={elapsed}
   399→              running={running}
   400→              borderImageUrl={borderImageUrl}
   401→            />
   402→            {selectedBuild.skillOrder && selectedBuild.skillOrder.length > 0 && (
   403→              <SkillOrderSection skillOrder={selectedBuild.skillOrder} />
   404→            )}
   405→          </>
   406→        )}
   407→      </section>
   408→    </div>
   409→  );
   410→}
