import { useState, useEffect, useRef } from "react";
import TimeIndicatorModel from "./components/TimeIndicatorModel";
import TopHudWebGL from "./components/TopHudWebGL";
import { decodeBLP, getBLPImageData } from "war3-model";
import { useCurrentRace, RACE_PREFIXES, setCurrentRace } from "./state/race";
import { getCount, setCount } from "./state/counter";
import { usePage, setPage } from "./state/page";
import type { Race } from "./lib/types";
import HeroSection from "./components/sections/HeroSection";
import FactionPreviewSection from "./components/sections/FactionPreviewSection";
import {
  ButtonsSection,
  ControlsSection,
  ButtonShowcaseSection,
  ResourceCounterSection,
  CommandCardSection,
  UnitQueueSection,
  TooltipSection,
  PortraitFrameSection,
  BarsSection,
} from "./components/sections/ShowcaseSection";
import DesignTokensSection from "./components/sections/DesignTokensSection";
import AccessibilitySection from "./components/sections/AccessibilitySection";
import HelloSection from "./components/sections/HelloSection";
import CounterSection from "./components/sections/CounterSection";
import BuildOrdersSection from "./components/sections/BuildOrderSection";
import GlueSmallButton from "./components/GlueSmallButton";
import BundleSizeSection from "./components/sections/BundleSizeSection";
import FAQSection from "./components/sections/FAQSection";
import FooterSection from "./components/sections/FooterSection";
import BordersSection from "./components/sections/BordersSection";
import RaceInfoSection from "./components/sections/RaceInfoSection";
import { PAGE_REGISTRY } from "./pages";
import LoadingScreen from "./components/LoadingScreen";

const topHudHeightVw = 4;
const clockWidthVw = 16;
const raceButtons: Race[] = ["Human", "Orc", "NightElf", "Undead"];
const compactTopHudBreakpointPx = 600;
const menuFrameVariantOrder: Record<string, number> = {
  Border: 0,
  BorderSingle: 1,
  Large: 2,
  LargeSingle: 3,
  Small: 4,
  SmallSingle: 5,
  Multiplayer: 6,
  Tiny: 7,
};

const upperButtonLeftVw = 0.25; // 0.002 * 125 from UpperButtonBar.fdf
const upperButtonTopVw = 0;
const upperButtonWidthVw = 10.625; // 0.085 * 125
const upperButtonHeightVw = 2.75; // 0.022 * 125
const upperButtonTexWidth = 0.6640625;
const upperButtonTexHeight = 0.171875;
const upperButtonBgSizeX = (1 / upperButtonTexWidth) * 100;
const upperButtonBgSizeY = (1 / upperButtonTexHeight) * 100;
const upperButtonPressedOffsetX = 0.125; // 0.001 * 125
const upperButtonPressedOffsetY = -0.125; // -0.001 * 125
const glueButtonPressedOffsetXPx = -2; // FDF ButtonPushedTextOffset X -0.002f
const glueButtonPressedOffsetYPx = 3; // FDF ButtonPushedTextOffset Y -0.003f (down in screen space)
const escButtonPressedOffsetXPx = 2; // FDF ButtonPushedTextOffset X 0.002f
const escButtonPressedOffsetYPx = 2; // FDF ButtonPushedTextOffset Y -0.002f (down in screen space)

function upperButtonPosY(offset: number): string {
  return `${(offset / (1 - upperButtonTexHeight)) * 100}%`;
}

const upperButtonNormalPosY = upperButtonPosY(0);
const upperButtonPushedPosY = upperButtonPosY(0.25);
const upperButtonHighlightPosY = upperButtonPosY(0.75);

const resourceBarWidthVw = 42.28515625; // 0.33828125 * 125 (same UI scale used by top HUD tiles)
const resourceBarHeightOfTopHud = 0.68125; // 0.0218 / 0.032 from ResourceBar.fdf + ConsoleUI.fdf
const resourceTextHeightOfTopHud = 0.3125; // 0.01 / 0.032
const resourceBarTopOffsetOfTopHud = 0.0;
const resourceBarRightOffsetVw = 0.390625; // 0.003125 * 125
const iconSizePercentOfBarHeight = 75.258;
const iconTopPercentOfBarHeight = 14.335;

import { useState } from 'react';
import type { Renderer } from '../../renderer/Renderer';
import Checkbox from '../Checkbox';
import RadioButton from '../RadioButton';
import Slider from '../Slider';
import EditBox from '../EditBox';

interface Props {
  renderer: Renderer;
}

export default function ControlsSection(props: Props) {
  const [selectedRadio, setSelectedRadio] = useState(0);

  return (
    <div className="tab-content">
      <div className="section-card">
        <h2>EscMenu Controls</h2>
        <p className="section-desc">Race-specific checkboxes, radio buttons, sliders, and edit boxes from the in-game Escape Menu.</p>
        <div className="menu-components-grid">
          <div className="menu-widget">
            <h3>Checkboxes</h3>
            <Checkbox label="Show Health Bars" initialChecked renderer={props.renderer} />
            <Checkbox label="Show Mana Bars" renderer={props.renderer} />
            <Checkbox label="Formation Toggle" initialChecked renderer={props.renderer} />
          </div>

          <div className="menu-widget">
            <h3>Radio Buttons</h3>
            <RadioButton label="Low" selected={selectedRadio === 0} onSelect={() => setSelectedRadio(0)} renderer={props.renderer} />
            <RadioButton label="Medium" selected={selectedRadio === 1} onSelect={() => setSelectedRadio(1)} renderer={props.renderer} />
            <RadioButton label="High" selected={selectedRadio === 2} onSelect={() => setSelectedRadio(2)} renderer={props.renderer} />
          </div>

          <div className="menu-widget">
            <h3>Sliders</h3>
            <Slider label="Music Volume" initialValue={0.7} renderer={props.renderer} />
            <Slider label="SFX Volume" initialValue={0.85} renderer={props.renderer} />
            <Slider label="Mouse Speed" initialValue={0.5} renderer={props.renderer} />
          </div>

          <div className="menu-widget">
            <h3>Edit Boxes (Human)</h3>
            <EditBox text="Player Name" renderer={props.renderer} />
            <EditBox text="Azeroth-1" renderer={props.renderer} />
          </div>
        </div>
      </div>
    </div>
  );
}

