            </EscOptionButton>
            <EscOptionButton onClick={() => setPage("showcase")}>
              {"See\u00A0"}
              <span className="button-hotkey">C</span>omponents
            </EscOptionButton>
          </>
        }
      />
    </div>
  );
}

