    86→
    87→export class Renderer {
    88→  ctx = new GLContext();
    89→  texManager = new TextureManager();
    90→  batcher = new QuadBatcher();
    91→  blend = new BlendManager();
    92→
    93→  raceTex!: RaceTextures;
    94→  private skyScrollTime = 0;
    95→  private rafId = 0;
    96→  private viewportRef: (() => HTMLElement) | null = null;
    97→
    98→  // Element registries
    99→  checkboxes: CheckboxReg[] = [];
   100→  radios: RadioReg[] = [];
   101→  sliders: SliderReg[] = [];
   102→  editBoxes: EditBoxReg[] = [];
   103→  glueButtons: GlueButtonReg[] = [];
   104→  glueMenuFrames: GlueMenuFrameReg[] = [];
   105→  optionButtons: OptionButtonReg[] = [];
   106→  tooltips: TooltipReg[] = [];
   107→  statBars: StatBarReg[] = [];
   108→  loadingBars: LoadingBarReg[] = [];
   109→  menuPanels: MenuPanelReg[] = [];
   110→  upperButtons: UpperButtonReg[] = [];
   111→  resourceIcons: ResourceIconReg[] = [];
   112→
   113→  init(canvas: HTMLCanvasElement) {
   114→    this.ctx.init(canvas);
   115→    this.texManager.init(this.ctx.gl);
   116→    this.batcher.init(this.ctx);
   117→    this.blend.init(this.ctx, this.batcher);
   118→    // Wire texManager into ctx for QuadBatcher's whiteTex access
   119→    (this.ctx as any)._texManager = this.texManager;
   120→  }
   121→
   122→  setViewportRef(ref: () => HTMLElement) {
   123→    this.viewportRef = ref;
   124→  }
   125→
   126→  loadRace(race: Race) {
   127→    this.raceTex = loadRaceTextures(race, this.texManager);
   128→  }
   129→
   130→  preloadAll() {
   131→    preloadAllRaces(this.texManager);
   132→  }
   133→
   134→  start() {
   135→    const loop = (_timestamp: number) => {
   136→      this.rafId = requestAnimationFrame(loop);
   137→      this.renderFrame();
   138→    };
   139→    this.rafId = requestAnimationFrame(loop);
   140→  }
   141→
   142→  destroy() {
   143→    cancelAnimationFrame(this.rafId);
   144→    this.ctx.destroy();
   145→  }
   146→
   147→  private renderFrame() {
   148→    const { ctx, batcher, blend } = this;
   149→    const gl = ctx.gl;
   150→    if (ctx.canvasW === 0 || ctx.canvasH === 0) return;
   151→    if (!this.raceTex) return;
   152→
   153→    gl.clearColor(0, 0, 0, 0);
   154→    gl.clear(gl.COLOR_BUFFER_BIT | gl.STENCIL_BUFFER_BIT);
   155→
   156→    blend.useProgram(ctx.quadProg);
   157→    gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   158→    gl.uniform1i(ctx.quadLocs.tex, 0);
   159→    gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   160→    blend.setBlend('BLEND');
   161→    batcher.batchTex = null;
   162→
   163→    const vw = ctx.canvasW / 100;
   164→    const topHudH = 4 * vw;
   165→    const hudBarH = parseFloat(getComputedStyle(document.documentElement).getPropertyValue('--hud-height')) || 240;
   166→
   167→    this.renderTopHud(vw, topHudH);
   168→    this.renderBottomHud(hudBarH);
   169→    this.renderUpperButtons();
   170→    this.renderResourceIcons();
   171→
   172→    // Viewport scissor
   173→    if (this.viewportRef) {
   174→      const vp = this.viewportRef();
   175→      if (vp) {
   176→        const vpRect = vp.getBoundingClientRect();
   177→        gl.enable(gl.SCISSOR_TEST);
   178→        gl.scissor(
   179→          vpRect.left * ctx.dpr,
   180→          (ctx.canvasH - vpRect.bottom) * ctx.dpr,
   181→          vpRect.width * ctx.dpr,
   182→          vpRect.height * ctx.dpr
   183→        );
   184→        this.renderViewportComponents(vpRect);
   185→        gl.disable(gl.SCISSOR_TEST);
   186→      }
   187→    }
   188→
   189→    batcher.flush();
   190→  }
   191→
   192→  private renderTopHud(vw: number, topHudH: number) {
   193→    const { ctx, batcher, blend, raceTex } = this;
   194→    const gl = ctx.gl;
   195→
   196→    const t1w = 32 * vw;
   197→    batcher.drawQuad(0, 0, t1w, topHudH, raceTex.topTile1, 0, 0, 1, 1);
   198→    const t2w = 10.875 * vw;
   199→    batcher.drawQuad(t1w, 0, t2w, topHudH, raceTex.topTile2, 0, 0, 0.34, 1);
   200→    const centerGap = ctx.canvasW - (32 + 10.875 + 6.625 + 32 + 4) * vw;
   201→    const rightStart = (32 + 10.875) * vw + centerGap;
   202→    const t3w = 6.625 * vw;
   203→    batcher.drawQuad(rightStart, 0, t3w, topHudH, raceTex.topTile2, 0.793, 0, 1, 1);
   204→    const t4w = 32 * vw;
   205→    batcher.drawQuad(rightStart + t3w, 0, t4w, topHudH, raceTex.topTile3, 0, 0, 1, 1);
   206→    const t5w = 4 * vw;
   207→    batcher.drawQuad(rightStart + t3w + t4w, 0, t5w, topHudH, raceTex.topTile4, 0, 0, 1, 1);
   208→
   209→    // Time indicator is rendered by the dedicated MDX clock component.
   210→  }
   211→
   212→  private renderBottomHud(hudBarH: number) {
   213→    const { ctx, batcher, raceTex } = this;
   214→    const y = ctx.canvasH - hudBarH;
   215→    const total = 1600;
   216→    const w1 = (512 / total) * ctx.canvasW;
   217→    const w2 = (512 / total) * ctx.canvasW;
   218→    const w3 = (512 / total) * ctx.canvasW;
   219→    const w4 = (64 / total) * ctx.canvasW;
   220→    batcher.drawQuad(0, y, w1, hudBarH, raceTex.hudTile1, 0, 0, 1, 1);
   221→    batcher.drawQuad(w1, y, w2, hudBarH, raceTex.hudTile2, 0, 0, 1, 1);
   222→    batcher.drawQuad(w1 + w2, y, w3, hudBarH, raceTex.hudTile3, 0, 0, 1, 1);
   223→    batcher.drawQuad(w1 + w2 + w3, y, w4, hudBarH, raceTex.hudTile4, 0, 0, 1, 1);
   224→  }
   225→
   226→  private renderUpperButtons() {
   227→    const { batcher, blend, ctx, raceTex } = this;
   228→    const gl = ctx.gl;
   229→
   230→    for (const btn of this.upperButtons) {
   231→      const el = btn.ref();
   232→      if (!el) continue;
   233→      const rect = el.getBoundingClientRect();
   234→      if (rect.width === 0) continue;
   235→
   236→      const atlasPath = `war3/Widgets/Console/${btn.race}/${RACE_PREFIXES[btn.race].lower}-console-buttonstates2.png`;
   237→      const atlasEntry = this.texManager.load(atlasPath);
   238→
   239→      const u0 = 0, u1 = 0.664;
   240→      let v0 = 0, v1 = 0.172;
   241→      if (btn.pressed()) { v0 = 0.25; v1 = 0.422; }
   242→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, atlasEntry, u0, v0, u1, v1);
   243→
   244→      if (btn.hovered() && !btn.pressed()) {
   245→        batcher.flush();
   246→        blend.setBlend('ADD');
   247→        batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, atlasEntry, u0, 0.75, u1, 0.922);
   248→        batcher.flush();
   249→        blend.setBlend('BLEND');
   250→        batcher.batchTex = null;
   251→      }
   252→    }
   253→  }
   254→
   255→  private renderResourceIcons() {
   256→    const { batcher, raceTex } = this;
   257→    for (const icon of this.resourceIcons) {
   258→      const el = icon.ref();
   259→      if (!el) continue;
   260→      const rect = el.getBoundingClientRect();
   261→      if (rect.width === 0) continue;
   262→      let texEntry: TextureEntry;
   263→      if (icon.type === 'gold') texEntry = raceTex.gold;
   264→      else if (icon.type === 'lumber') texEntry = raceTex.lumber;
   265→      else texEntry = raceTex.supply;
   266→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, texEntry, 0, 0, 1, 1);
   267→    }
   268→  }
   269→
   270→  private renderViewportComponents(vpRect: DOMRect) {
   271→    const { ctx, batcher, blend } = this;
   272→    const gl = ctx.gl;
   273→
   274→    blend.useProgram(ctx.quadProg);
   275→    gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   276→    gl.uniform1i(ctx.quadLocs.tex, 0);
   277→    gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   278→    batcher.batchTex = null;
   279→
   280→    this.renderGlueButtons(vpRect);
   281→    this.renderEscMenuComponents(vpRect);
   282→    this.renderTooltips(vpRect);
   283→    this.renderBars(vpRect);
   284→    this.renderLoadingBars(vpRect);
   285→    this.renderMenuPanels(vpRect);
   286→  }
   287→
   288→  private isVisible(rect: DOMRect, vpRect: DOMRect): boolean {
   289→    return rect.width > 0 && rect.bottom >= vpRect.top && rect.top <= vpRect.bottom;
   290→  }
   291→
   292→  private renderGlueButtons(vpRect: DOMRect) {
   293→    const { ctx, batcher, blend, raceTex, texManager } = this;
   294→    const gl = ctx.gl;
   295→
   296→    for (const btn of this.glueButtons) {
   297→      const el = btn.ref();
   298→      if (!el) continue;
   299→      const rect = el.getBoundingClientRect();
   300→      if (!this.isVisible(rect, vpRect)) continue;
   301→
   302→      let bgPath: string, borderPath: string;
   303→      if (btn.disabled) {
   304→        bgPath = btn.bgPath;
   305→        borderPath = btn.borderPath;
   306→      } else if (btn.pressed() && btn.bgDownPath) {
   307→        bgPath = btn.bgDownPath;
   308→        borderPath = btn.borderDownPath || btn.borderPath;
   309→      } else {
   310→        bgPath = btn.bgPath;
   311→        borderPath = btn.borderPath;
   312→      }
   313→
   314→      const bgEntry = texManager.loadRepeat(bgPath);
   315→      const borderEntry = borderPath ? texManager.load(borderPath) : null;
   316→      const corner = borderEntry && borderEntry.loaded
   317→        ? Math.floor(Math.min(borderEntry.width / 8, rect.height * 0.35))
   318→        : Math.floor(rect.height * 0.35);
   319→      const inset = Math.round(corner * 0.25);
   320→
   321→      drawNineSlice(ctx, batcher, blend, rect.left, rect.top, rect.width, rect.height,
   322→        borderEntry, corner, bgEntry, 32, inset);
   323→
   324→      if (btn.hovered() && !btn.pressed() && btn.hoverPath) {
   325→        batcher.flush();
   326→        blend.setBlend('ADD');
   327→        const hoverEntry = texManager.load(btn.hoverPath);
   328→        batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, hoverEntry, 0, 0, 1, 1);
   329→        batcher.flush();
   330→        blend.setBlend('BLEND');
   331→        batcher.batchTex = null;
   332→        blend.useProgram(ctx.quadProg);
   333→        gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   334→        gl.uniform1i(ctx.quadLocs.tex, 0);
   335→        gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   336→      }
   337→    }
   338→
   339→    // Menu frames
   340→    for (const frame of this.glueMenuFrames) {
   341→      const el = frame.ref();
   342→      if (!el) continue;
   343→      const rect = el.getBoundingClientRect();
   344→      if (!this.isVisible(rect, vpRect)) continue;
   345→      const entry = this.texManager.load(frame.imgSrc);
   346→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, entry, 0, 0, 1, 1);
   347→    }
   348→  }
   349→
   350→  private renderEscMenuComponents(vpRect: DOMRect) {
   351→    const { ctx, batcher, blend, raceTex } = this;
   352→    const gl = ctx.gl;
   353→
   354→    // Option buttons
   355→    for (const btn of this.optionButtons) {
   356→      const el = btn.ref();
   357→      if (!el) continue;
   358→      const rect = el.getBoundingClientRect();
   359→      if (!this.isVisible(rect, vpRect)) continue;
   360→
   361→      batcher.flush();
   362→      blend.useProgram(ctx.tiledProg);
   363→      gl.uniform2f(ctx.tiledLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   364→      gl.uniform1i(ctx.tiledLocs.tex, 0);
   365→      gl.uniform2f(ctx.tiledLocs.quadSize, rect.width, rect.height);
   366→      gl.uniform2f(ctx.tiledLocs.tileSize, 256, 256);
   367→      gl.uniform1i(ctx.tiledLocs.alphaMode, 0);
   368→      batcher.batchTex = null;
   369→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.escBtnBgTiled, 0, 0, 1, 1);
   370→      batcher.flush();
   371→
   372→      blend.useProgram(ctx.quadProg);
   373→      gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   374→      gl.uniform1i(ctx.quadLocs.tex, 0);
   375→      gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   376→      batcher.batchTex = null;
   377→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.escBtnBorder, 0, 0, 1, 1);
   378→
   379→      if (btn.hovered()) {
   380→        batcher.flush();
   381→        blend.setBlend('ADD');
   382→        batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.escBtnHighlight, 0, 0, 1, 1);
   383→        batcher.flush();
   384→        blend.setBlend('BLEND');
   385→        batcher.batchTex = null;
   386→      }
   387→    }
   388→
   389→    // Checkboxes
   390→    for (const cb of this.checkboxes) {
   391→      const vis = cb.visualRef();
   392→      if (!vis) continue;
   393→      const rect = vis.getBoundingClientRect();
   394→      if (!this.isVisible(rect, vpRect)) continue;
   395→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.cbBg, 0, 0, 1, 1);
   396→      if (cb.checked()) {
   397→        batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.cbCheck, 0, 0, 1, 1);
   398→      }
   399→    }
   400→
   401→    // Radios
   402→    for (const rb of this.radios) {
   403→      const vis = rb.visualRef();
   404→      if (!vis) continue;
   405→      const rect = vis.getBoundingClientRect();
   406→      if (!this.isVisible(rect, vpRect)) continue;
   407→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.rbBg, 0, 0, 1, 1);
   408→      if (rb.selected()) {
   409→        batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.rbDot, 0, 0, 1, 1);
   410→      }
   411→    }
   412→
   413→    // Sliders
   414→    for (const slider of this.sliders) {
   415→      const el = slider.ref();
   416→      if (!el) continue;
   417→      const rect = el.getBoundingClientRect();
   418→      if (!this.isVisible(rect, vpRect)) continue;
   419→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.sliderBg, 0, 0, 1, 1);
   420→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.sliderBorder, 0, 0, 1, 1);
   421→      const val = slider.value();
   422→      const knobW = 20, knobH = 28;
   423→      const knobX = rect.left + val * rect.width - knobW / 2;
   424→      const knobY = rect.top + rect.height / 2 - knobH / 2;
   425→      batcher.drawQuad(knobX, knobY, knobW, knobH, raceTex.sliderKnob, 0, 0, 1, 1);
   426→    }
   427→
   428→    // Edit boxes
   429→    for (const eb of this.editBoxes) {
   430→      const el = eb.ref();
   431→      if (!el) continue;
   432→      const rect = el.getBoundingClientRect();
   433→      if (!this.isVisible(rect, vpRect)) continue;
   434→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.ebBg, 0, 0, 1, 1);
   435→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.ebBorder, 0, 0, 1, 1);
   436→    }
   437→  }
   438→
   439→  private renderTooltips(vpRect: DOMRect) {
   440→    const { ctx, batcher, blend, raceTex } = this;
   441→    const gl = ctx.gl;
   442→
   443→    for (const tt of this.tooltips) {
   444→      const el = tt.ref();
   445→      if (!el) continue;
   446→      const rect = el.getBoundingClientRect();
   447→      if (!this.isVisible(rect, vpRect)) continue;
   448→
   449→      batcher.flush();
   450→      blend.useProgram(ctx.tiledProg);
   451→      gl.uniform2f(ctx.tiledLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   452→      gl.uniform1i(ctx.tiledLocs.tex, 0);
   453→      gl.uniform2f(ctx.tiledLocs.quadSize, rect.width, rect.height);
   454→      gl.uniform2f(ctx.tiledLocs.tileSize, 64, 64);
   455→      gl.uniform1i(ctx.tiledLocs.alphaMode, 0);
   456→      batcher.batchTex = null;
   457→      blend.setBlend('BLEND');
   458→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.tooltipBgTiled, 0, 0, 1, 1);
   459→      batcher.flush();
   460→
   461→      blend.useProgram(ctx.quadProg);
   462→      gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   463→      gl.uniform1i(ctx.quadLocs.tex, 0);
   464→      gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   465→      batcher.batchTex = null;
   466→
   467→      const bw = 2;
   468→      const br = 0.784, bg = 0.659, bb = 0.306;
   469→      batcher.drawQuad(rect.left, rect.top, rect.width, bw, null, 0,0,1,1, br, bg, bb, 1);
   470→      batcher.drawQuad(rect.left, rect.bottom - bw, rect.width, bw, null, 0,0,1,1, br, bg, bb, 1);
   471→      batcher.drawQuad(rect.left, rect.top, bw, rect.height, null, 0,0,1,1, br, bg, bb, 1);
   472→      batcher.drawQuad(rect.right - bw, rect.top, bw, rect.height, null, 0,0,1,1, br, bg, bb, 1);
   473→    }
   474→  }
   475→
   476→  private renderBars(vpRect: DOMRect) {
   477→    const { batcher, raceTex } = this;
   478→
   479→    for (const bar of this.statBars) {
   480→      const el = bar.ref();
   481→      if (!el) continue;
   482→      const rect = el.getBoundingClientRect();
   483→      if (!this.isVisible(rect, vpRect)) continue;
   484→
   485→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, null, 0,0,1,1, 0.067, 0.067, 0.067, 1);
   486→
   487→      const pct = bar.fillPercent();
   488→      const fillPx = rect.width * pct / 100;
   489→      if (fillPx > 0) {
   490→        let fillTex: TextureEntry | null = null;
   491→        if (bar.type === 'health') fillTex = raceTex.healthFill;
   492→        else if (bar.type === 'mana') fillTex = raceTex.manaFill;
   493→        else if (bar.type === 'xp') fillTex = raceTex.xpFill;
   494→        else if (bar.type === 'build') fillTex = raceTex.buildFill;
   495→        if (fillTex) {
   496→          batcher.drawQuad(rect.left, rect.top, fillPx, rect.height, fillTex, 0, 0, fillPx / rect.height, 1);
   497→        }
   498→      }
   499→
   500→      if (bar.hasBorder) {
   501→        let borderTex: TextureEntry | null = null;
   502→        if (bar.type === 'xp') borderTex = raceTex.xpBorder;
   503→        else if (bar.type === 'build') borderTex = raceTex.buildBorder;
   504→        if (borderTex) {
