// Effect: esc editbox canvas
useEffect(() => {
  const canvas = escEditboxCanvasRef.current;
  const bgUrlVal = escMenuBgUrl;
  const borderUrlVal = escMenuBorderUrl;
  if (!canvas || !bgUrlVal || !borderUrlVal) return;
  let cancelled = false;

  void Promise.all([
    loadDataUrlImage(bgUrlVal),
    loadDataUrlImage(borderUrlVal),
  ])
    .then(([bgImg, borderImg]) => {
      if (cancelled) return;
      const h = canvas.clientHeight || 1;
      drawTemplateNineSliceToCanvas(canvas, bgImg, borderImg, {
        cornerPx: h * escControlCornerRatio,
        insetPx: escEditboxCanvasFillInsetPx,
        tileBackground: true,
        tileHorizontalEdges: true,
        opaqueBaseFill: "#000",
        fillCornerMaxPx: escControlFillCornerCapPx,
      });
    })
    .catch((err) => console.error(err));

  return () => {
    cancelled = true;
  };
}, [escMenuBgUrl, escMenuBorderUrl, activePage]);

// Effect: esc editbox disabled canvas
useEffect(() => {
  const canvas = escEditboxDisabledCanvasRef.current;
  const bgUrlVal = escMenuBgUrl;
  const borderUrlVal = escMenuBorderUrl;
  if (!canvas || !bgUrlVal || !borderUrlVal) return;
  let cancelled = false;

  void Promise.all([
    loadDataUrlImage(bgUrlVal),
    loadDataUrlImage(borderUrlVal),
  ])
