import { useState } from "react";
import type { Renderer } from "../../renderer/Renderer";
import type { Race } from "../../lib/types";
import EditBox from "../EditBox";
import GlueDropdown from "../GlueDropdown";
import GlueSmallButton from "../GlueSmallButton";
import GlueBorderedButton from "../GlueBorderedButton";
import { importBuilds } from "../../state/buildOrders";

const RACES: Race[] = ["Human", "Orc", "NightElf", "Undead"];
const RACE_LABELS: Record<Race, string> = {
  Human: "Human",
  Orc: "Orc",
  NightElf: "Night Elf",
  Undead: "Undead",
};
const DIFFICULTIES = ["Beginner", "Intermediate", "Advanced"] as const;
type Difficulty = (typeof DIFFICULTIES)[number];

interface StepRow {
  time: string;
  instruction: string;
  food: string;
}

interface Props {
  renderer: Renderer;
}

export default function BuildOrderInputSection({ renderer }: Props) {
  const [name, setName] = useState("");
  const [race, setRace] = useState<Race>("Human");
  const [vs, setVs] = useState("");
  const [difficulty, setDifficulty] = useState<Difficulty>("Beginner");
  const [description, setDescription] = useState("");
  const [steps, setSteps] = useState<StepRow[]>([
    { time: "0:00", instruction: "", food: "" },
  ]);
  const [status, setStatus] = useState("");

  function updateStep(index: number, field: keyof StepRow, value: string) {
    setSteps((prev) =>
      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
    );
  }

  function addStep() {
    setSteps((prev) => [
      ...prev,
      { time: "", instruction: "", food: "" },
    ]);
  }

  function removeStep(index: number) {
    setSteps((prev) => prev.filter((_, i) => i !== index));
  }

  function handleSubmit() {
    const build = {
      name,
      race,
      vs: vs || undefined,
      difficulty,
      description,
      steps: steps.map((s, i) => ({
        order: i + 1,
        time: s.time,
        instruction: s.instruction,
        food: s.food,
      })),
    };

    const count = importBuilds([build]);
    if (count > 0) {
      setStatus("Build order added!");
      setName("");
      setVs("");
      setDescription("");
      setSteps([{ time: "0:00", instruction: "", food: "" }]);
    } else {
      setStatus("Please fill in Name and at least one step.");
    }
    setTimeout(() => setStatus(""), 4000);
  }

  return (
    <section className="section-card build-order-input-section">
      <h4 className="skill-order-title">Add Build Order</h4>

      <div className="build-order-input-fields">
        <div className="build-order-input-row">
          <label className="build-order-input-label">Name</label>
          <EditBox
            value={name}
            placeholder="Build order name"
            onChange={setName}
            renderer={renderer}
          />
        </div>

        <div className="build-order-input-row">
          <label className="build-order-input-label">Race</label>
          <GlueDropdown
            options={RACES}
            value={race}
            onChange={(v) => setRace(v as Race)}
            label={(v) => RACE_LABELS[v as Race] ?? v}
          />
        </div>

        <div className="build-order-input-row">
          <label className="build-order-input-label">vs (optional)</label>
          <EditBox
            value={vs}
            placeholder="e.g. Human, all"
            onChange={setVs}
            renderer={renderer}
          />
        </div>

        <div className="build-order-input-row">
          <label className="build-order-input-label">Difficulty</label>
          <GlueDropdown
            options={DIFFICULTIES}
            value={difficulty}
            onChange={(v) => setDifficulty(v as Difficulty)}
          />
        </div>

        <div className="build-order-input-row">
          <label className="build-order-input-label">Description</label>
          <EditBox
            value={description}
            placeholder="Short description"
            onChange={setDescription}
            renderer={renderer}
          />
        </div>
      </div>

      <div className="build-order-input-steps">
        <h5 className="build-order-input-steps-title">Steps</h5>
        <table className="build-steps-table build-order-input-steps-table">
          <thead>
            <tr>
              <th>#</th>
              <th>Time</th>
              <th>Instruction</th>
              <th>Food</th>
              <th></th>
            </tr>
          </thead>
          <tbody>
            {steps.map((step, i) => (
              <tr key={i} className="build-order-input-step-row">
                <td className="build-step-order">{i + 1}</td>
                <td>
                  <EditBox
                    value={step.time}
                    placeholder="0:00"
                    onChange={(v) => updateStep(i, "time", v)}
                    renderer={renderer}
                  />
                </td>
                <td>
                  <EditBox
                    value={step.instruction}
                    placeholder="Instruction"
                    onChange={(v) => updateStep(i, "instruction", v)}
                    renderer={renderer}
                  />
                </td>
                <td>
                  <EditBox
                    value={step.food}
                    placeholder="5/10"
                    onChange={(v) => updateStep(i, "food", v)}
                    renderer={renderer}
                  />
                </td>
                <td>
                  {steps.length > 1 && (
                    <GlueSmallButton onClick={() => removeStep(i)}>
                      ✕
                    </GlueSmallButton>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div className="build-order-input-step-actions">
          <GlueSmallButton onClick={addStep}>+ Add Step</GlueSmallButton>
        </div>
      </div>

      <div className="build-order-input-submit">
        <GlueBorderedButton onClick={handleSubmit}>Add Build</GlueBorderedButton>
      </div>

      {status && <div className="build-import-status">{status}</div>}
    </section>
  );
}

import { useCallback, useEffect, useRef, useState } from "react";
import {
  useTimerRunning,
  useElapsedSeconds,
  startTimer,
  pauseTimer,
  resetTimer,
} from "../../state/timer";
import { useCurrentRace, setCurrentRace } from "../../state/race";
import type { Race } from "../../lib/types";
import GlueSmallButton from "../GlueSmallButton";
import GlueBorderedButton from "../GlueBorderedButton";
import GlueDropdown from "../GlueDropdown";
import GlueScrollbar from "../GlueScrollbar";
import { useBuildOrders, importBuilds } from "../../state/buildOrders";
import type { BuildOrder } from "../../data/buildOrders";
import HeroPortraitModel from "../HeroPortraitModel";
import { RACE_PREFIXES } from "../../state/race";

const RACES: Race[] = ["Human", "Orc", "NightElf", "Undead"];
const RACE_LABELS: Record<Race, string> = {
  Human: "Human",
  Orc: "Orc",
  NightElf: "Night Elf",
  Undead: "Undead",
};
import {
  loadBlpDataUrl,
  loadDataUrlImage,
  composeBorderImageFromAtlas,
} from "../../utils/glueButton";
import SkillOrderSection from "../SkillOrderSection";
import BuildOrderInputSection from "./BuildOrderInputSection";
import { renderer } from "../../renderer/rendererInstance";

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

function parseStepTime(time: string): number {
  const [m, s] = time.split(":").map(Number);
  return m * 60 + (s ?? 0);
}

function getCardBorderPath(race: Race | null): string {
  if (race === "Orc") return "/buttons/esc/orc/orc-options-menu-border.blp";
  if (race === "NightElf")
    return "/buttons/esc/nightelf/nightelf-options-menu-border.blp";
  if (race === "Undead")
    return "/buttons/esc/undead/undead-options-menu-border.blp";
  return "/buttons/esc/human/human-options-menu-border.blp";
}

function useCardBorderImage(race: Race | null): string {
  const [borderImageUrl, setBorderImageUrl] = useState("");

  useEffect(() => {
    let cancelled = false;
    const path = getCardBorderPath(race);
    void loadBlpDataUrl(path)
      .then((url) => loadDataUrlImage(url))
      .then((img) => {
        if (cancelled) return;
        setBorderImageUrl(composeBorderImageFromAtlas(img));
      })
      .catch((err) => console.error(err));
    return () => {
      cancelled = true;
    };
  }, [race]);

  return borderImageUrl;
}

function useSupplyIcon(): string {
  const [url, setUrl] = useState("");
  useEffect(() => {
    void loadBlpDataUrl("/resources/ResourceSupply.blp").then(setUrl);
  }, []);
  return url;
}

const DIFFICULTY_CLASS: Record<string, string> = {
  Beginner: "build-card-difficulty--beginner",
  Intermediate: "build-card-difficulty--intermediate",
  Advanced: "build-card-difficulty--advanced",
};

interface BuildCardProps {
  build: BuildOrder;
  elapsed: number;
  running: boolean;
  borderImageUrl: string;
}

const VALID_RACES = new Set<string>(["Human", "Orc", "NightElf", "Undead"]);

function BuildCard({ build, elapsed, running, borderImageUrl }: BuildCardProps) {
  const tableRef = useRef<HTMLDivElement>(null);
  const [scrollPct, setScrollPct] = useState(0);
  const scrollingFromBar = useRef(false);
  const supplyIconUrl = useSupplyIcon();
  const buildRace = VALID_RACES.has(build.race)
    ? (build.race as Race)
    : null;

  const activeStepIndex = (() => {
    let idx = -1;
    for (let i = 0; i < build.steps.length; i++) {
      if (parseStepTime(build.steps[i].time) <= elapsed) idx = i;
    }
    return idx;
  })();

  // Sync native scroll → scrollbar percentage
  useEffect(() => {
    const el = tableRef.current;
    if (!el) return;
    const handler = () => {
      if (scrollingFromBar.current) return;
      const maxScroll = el.scrollHeight - el.clientHeight;
      if (maxScroll <= 0) {
        setScrollPct(0);
        return;
      }
      setScrollPct((el.scrollTop / maxScroll) * 100);
    };
    el.addEventListener("scroll", handler, { passive: true });
    return () => el.removeEventListener("scroll", handler);
  }, []);

  // Scrollbar → native scroll
  const handleScrollbarChange = useCallback((pct: number) => {
    setScrollPct(pct);
    const el = tableRef.current;
    if (!el) return;
    const maxScroll = el.scrollHeight - el.clientHeight;
    if (maxScroll <= 0) return;
    scrollingFromBar.current = true;
    el.scrollTop = (pct / 100) * maxScroll;
    requestAnimationFrame(() => {
      scrollingFromBar.current = false;
    });
  }, []);

  // Auto-scroll the active step into view
  useEffect(() => {
    if (activeStepIndex < 0 || !tableRef.current) return;
    const row = tableRef.current.querySelectorAll(".build-step-row")[
      activeStepIndex
    ] as HTMLElement | undefined;
    if (row) {
      row.scrollIntoView({ block: "nearest", behavior: "smooth" });
    }
  }, [activeStepIndex]);

  // border-image applied only to the active row; all rows already reserve
  // 6px transparent border space in CSS so nothing shifts.
  const activeBorderStyle: React.CSSProperties | undefined = borderImageUrl
    ? {
        borderImageSource: `url("${borderImageUrl}")`,
        borderImageSlice: 64,
        borderImageWidth: 1,
        borderImageRepeat: "round",
      }
    : undefined;

  return (
    <div className="build-card">
      {/* Left column */}
      <div className="build-card-info">
        <div className="build-card-header">
          {buildRace && (
            <div className="build-card-portrait">
              <div
                className="build-card-portrait-window"
                style={{
                  "--portrait-window-mask": `url("/console/${buildRace}/${RACE_PREFIXES[buildRace].tile}UIPortraitWindowMask.png")`,
                } as React.CSSProperties}
              >
                <HeroPortraitModel race={buildRace} />
              </div>
              <img
                src={`/console/${buildRace}/${RACE_PREFIXES[buildRace].tile}UIPortraitFrameCrop.png`}
                alt=""
                className="build-card-portrait-frame"
              />
            </div>
          )}
          <div className="build-card-header-text">
            <h4 className="build-card-title">{build.name}</h4>
            <div className="build-card-subtitle">
              {build.vs && (
                <span className="build-card-matchup">vs {build.vs}</span>
              )}
              {build.difficulty && (
                <span
                  className={`build-card-difficulty ${DIFFICULTY_CLASS[build.difficulty] ?? ""}`}
                >
                  {build.difficulty}
                </span>
              )}
            </div>
          </div>
        </div>

        <div className="build-card-body">
          {build.description && (
            <p className="build-card-desc">{build.description}</p>
          )}
          {build.note && <p className="build-card-note">{build.note}</p>}
          {build.keyTiming && (
            <div className="build-card-key-timing">
              <span className="build-card-key-timing-label">Key timing</span>{" "}
              {formatTime(build.keyTiming.minute * 60)} –{" "}
              {build.keyTiming.note}
            </div>
          )}
        </div>

        <div className="build-card-timer">
          <span className="build-card-elapsed">{formatTime(elapsed)}</span>
          <div className="build-card-controls">
            <GlueSmallButton onClick={running ? pauseTimer : startTimer}>
              {running ? "Pause" : "Start"}
            </GlueSmallButton>
            <GlueSmallButton
              onClick={resetTimer}
              disabled={elapsed === 0 && !running}
            >
              Reset
            </GlueSmallButton>
          </div>
        </div>
      </div>

      {/* Right column */}
      <div className="build-card-steps-wrapper">
        <div className="build-card-steps" ref={tableRef}>
          <table className="build-steps-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Time</th>
                <th>Instruction</th>
                <th>
                  {supplyIconUrl && (
                    <img src={supplyIconUrl} alt="" className="build-step-food-icon" />
                  )}
                  Food
                </th>
              </tr>
            </thead>
            <tbody>
              {build.steps.map((step, j) => {
                const isActive = j === activeStepIndex;
                const isPast = j < activeStepIndex;
                return (
                  <tr
                    key={j}
                    className={`build-step-row${isPast ? " build-step-row--past" : ""}${isActive ? " build-step-row--active" : ""}`}
                    style={isActive ? activeBorderStyle : undefined}
                  >
                    <td className="build-step-order">{step.order}</td>
                    <td className="build-step-time">{step.time}</td>
                    <td className="build-step-instruction">{step.instruction}</td>
                    <td className="build-step-food">
                      {supplyIconUrl && (
                        <img src={supplyIconUrl} alt="" className="build-step-food-icon" />
                      )}
                      {step.food}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <GlueScrollbar
          value={scrollPct}
          onChange={handleScrollbarChange}
        />
      </div>
    </div>
  );
}

export default function BuildOrdersSection() {
  const running = useTimerRunning();
  const elapsed = useElapsedSeconds();
  const currentRace = useCurrentRace();
  const borderImageUrl = useCardBorderImage(currentRace);
  const allBuilds = useBuildOrders();

  const relevantBuilds = allBuilds.filter(
    (b) => !currentRace || b.race === currentRace,
  );

  const [selectedIndex, setSelectedIndex] = useState(0);
  const [importStatus, setImportStatus] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reset selection and timer when race changes
  useEffect(() => {
    setSelectedIndex(0);
    resetTimer();
  }, [currentRace]);

  const selectedBuild =
    relevantBuilds.length > 0
      ? relevantBuilds[Math.min(selectedIndex, relevantBuilds.length - 1)]
      : null;

  // Build dropdown option keys — use indices as stable identifiers
  const optionKeys = relevantBuilds.map((_, i) => String(i));

  const handleImport = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = () => {
        try {
          const json = JSON.parse(reader.result as string);
          const count = importBuilds(json);
          if (count > 0) {
            setImportStatus(`Imported ${count} build${count > 1 ? "s" : ""}`);
          } else {
            setImportStatus("No valid builds found in file");
          }
        } catch {
          setImportStatus("Invalid JSON file");
        }
        // Clear so the same file can be re-imported
        e.target.value = "";
        setTimeout(() => setImportStatus(""), 4000);
      };
      reader.readAsText(file);
    },
    [],
  );

  return (
    <div className="tab-content">
      <section className="section-card build-orders-section">
        <div className="build-orders-toolbar">
          <h3>Build Orders</h3>
          <div className="build-orders-toolbar-actions">
            <div className="build-orders-race-picker">
              <GlueDropdown
                options={RACES}
                value={currentRace}
                onChange={(v) => setCurrentRace(v as Race)}
                label={(v) => RACE_LABELS[v as Race] ?? v}
              />
            </div>
            {relevantBuilds.length > 1 && (
              <GlueDropdown
                options={optionKeys}
                value={String(
                  Math.min(selectedIndex, relevantBuilds.length - 1),
                )}
                onChange={(v) => {
                  setSelectedIndex(Number(v));
                  resetTimer();
                }}
                label={(v) => relevantBuilds[Number(v)]?.name ?? ""}
              />
            )}
            <GlueBorderedButton onClick={handleImport}>Import</GlueBorderedButton>
            <input
              ref={fileInputRef}
              type="file"
              accept=".json"
              className="build-import-input"
              onChange={handleFileChange}
            />
          </div>
        </div>
        {importStatus && (
          <div className="build-import-status">{importStatus}</div>
        )}

        {!selectedBuild ? (
          <p className="build-card-empty">
            No build orders available for this race.
          </p>
        ) : (
          <>
            <BuildCard
              key={`${currentRace}-${selectedIndex}`}
              build={selectedBuild}
              elapsed={elapsed}
              running={running}
              borderImageUrl={borderImageUrl}
            />
            {selectedBuild.skillOrder && selectedBuild.skillOrder.length > 0 && (
              <SkillOrderSection skillOrder={selectedBuild.skillOrder} />
            )}
            <BuildOrderInputSection renderer={renderer} />
          </>
        )}
      </section>
    </div>
  );
}

