import { useEffect, useRef } from 'react';
import type { Renderer } from '../renderer/Renderer';

interface Props {
  text?: string;
  value?: string;
  placeholder?: string;
  onChange?: (v: string) => void;
  renderer: Renderer;
}

export default function EditBox(props: Props) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    props.renderer.editBoxes.push({ ref: () => ref.current! });
  }, []);

  return (
    <div ref={ref} className="wc3-editbox">
      <img className="eb-bg" src="" alt="" />
      <img className="eb-border" src="" alt="" />
      {props.onChange !== undefined ? (
        <input
          value={props.value ?? ''}
          placeholder={props.placeholder}
          onChange={(e) => props.onChange!(e.target.value)}
        />
      ) : (
        <div className="eb-text">{props.text}</div>
      )}
    </div>
  );
}

