import { useState } from "react";
import type { Race } from "../../lib/types";
import EscEditBox from "../EscEditBox";
import GlueDropdown from "../GlueDropdown";
import GlueSmallButton from "../GlueSmallButton";
import GlueBorderedButton from "../GlueBorderedButton";
import { importBuilds } from "../../state/buildOrders";

const RACES: Race[] = ["Human", "Orc", "NightElf", "Undead"];
const RACE_LABELS: Record<Race, string> = {
  Human: "Human",
  Orc: "Orc",
  NightElf: "Night Elf",
  Undead: "Undead",
};
const DIFFICULTIES = ["Beginner", "Intermediate", "Advanced"] as const;
type Difficulty = (typeof DIFFICULTIES)[number];

/** Known skill names whose BLP filename differs from a naive PascalCase transform. */
const SKILL_ICON_OVERRIDES: Record<string, string> = {
  "Holy Light": "BTNHolyBolt",
  "Bladestorm": "BTNWhirlwind",
  "Wind Walk": "BTNWindWalkOn",
  "Devotion Aura": "BTNDevotion",
  "Divine Shield": "BTNDivineIntervention",
  "Resurrection": "BTNResurrection",
  "Storm Bolt": "BTNStormBolt",
  "Thunder Clap": "BTNThunderClap",
  "Avatar": "BTNAvatar",
  "Flame Strike": "BTNWallOfFire",
  "Banish": "BTNBanish",
  "Phoenix": "BTNMarkOfFire",
  "Brilliance Aura": "BTNBrilliance",
  "Water Elemental": "BTNSummonWaterElemental",
  "Blizzard": "BTNBlizzard",
  "Mass Teleport": "BTNMassTeleport",
  "Feral Spirit": "BTNSpiritWolf",
  "Chain Lightning": "BTNChainLightning",
  "Earthquake": "BTNEarthquake",
  "Healing Wave": "BTNHealingWave",
  "Hex": "BTNHex",
  "Serpent Ward": "BTNSerpentWard",
  "Big Bad Voodoo": "BTNBigBadVoodoo",
  "War Stomp": "BTNWarStomp",
  "Endurance Aura": "BTNCommand",
  "Reincarnation": "BTNReincarnation",
  "Shadow Strike": "BTNShadowStrike",
  "Fan of Knives": "BTNFanOfKnives",
  "Blink": "BTNBlink",
  "Vengeance": "BTNVengeance",
  "Mana Burn": "BTNManaBurn",
  "Evasion": "BTNEvasion",
  "Metamorphosis": "BTNMetamorphosis",
  "Critical Strike": "BTNCriticalStrike",
  "Force of Nature": "BTNEnt",
  "Entangling Roots": "BTNEntanglingRoots",
  "Tranquility": "BTNTranquility",
  "Scout": "BTNSentinel",
  "Trueshot Aura": "BTNTrueShot",
  "Starfall": "BTNStarFall",
  "Frost Nova": "BTNGlacier",
  "Dark Ritual": "BTNDarkRitual",
  "Frost Armor": "BTNFrostArmor",
  "Death and Decay": "BTNDeathAndDecay",
  "Impale": "BTNImpale",
  "Spiked Carapace": "BTNThornShield",
  "Locust Swarm": "BTNLocustSwarm",
  "Death Coil": "BTNDeathCoil",
  "Unholy Aura": "BTNUnholyAura",
  "Animate Dead": "BTNAnimateDead",
  "Death Pact": "BTNDeathPact",
};

function skillToIconPath(skillName: string): string {
  const override = SKILL_ICON_OVERRIDES[skillName];
  if (override) return `/buttons/command/${override}.blp`;
  const pascal = skillName.replace(/\s+/g, "");
  return `/buttons/command/BTN${pascal}.blp`;
}

interface StepRow {
  time: string;
  instruction: string;
  food: string;
}

interface SkillRow {
  level: string;
  skill: string;
}

export default function BuildOrderInputSection() {
  const [name, setName] = useState("");
  const [race, setRace] = useState<Race>("Human");
  const [vs, setVs] = useState("");
  const [difficulty, setDifficulty] = useState<Difficulty>("Beginner");
  const [description, setDescription] = useState("");
  const [note, setNote] = useState("");
  const [keyTimingMinute, setKeyTimingMinute] = useState("");
  const [keyTimingNote, setKeyTimingNote] = useState("");
  const [steps, setSteps] = useState<StepRow[]>([
    { time: "0:00", instruction: "", food: "" },
  ]);
  const [skills, setSkills] = useState<SkillRow[]>([]);
  const [status, setStatus] = useState("");

  function updateStep(index: number, field: keyof StepRow, value: string) {
    setSteps((prev) =>
      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
    );
  }

  function addStep() {
    setSteps((prev) => [...prev, { time: "", instruction: "", food: "" }]);
  }

  function removeStep(index: number) {
    setSteps((prev) => prev.filter((_, i) => i !== index));
  }

  function updateSkill(index: number, field: keyof SkillRow, value: string) {
    setSkills((prev) =>
      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
    );
  }

  function addSkill() {
    setSkills((prev) => [
      ...prev,
      { level: String(prev.length + 1), skill: "" },
    ]);
  }

  function removeSkill(index: number) {
    setSkills((prev) => prev.filter((_, i) => i !== index));
  }

  function handleSubmit() {
    const keyTimingMin = Number(keyTimingMinute);
    const build = {
      name,
      race,
      vs: vs || undefined,
      difficulty,
      description,
      note: note || undefined,
      keyTiming:
        keyTimingMinute && keyTimingNote
          ? { minute: keyTimingMin, note: keyTimingNote }
          : undefined,
      steps: steps.map((s, i) => ({
        order: i + 1,
        time: s.time,
        instruction: s.instruction,
        food: s.food,
      })),
      skillOrder:
        skills.length > 0
          ? skills.map((s) => ({
              level: Number(s.level),
              skill: s.skill,
              icon: skillToIconPath(s.skill),
            }))
          : undefined,
    };

    const count = importBuilds([build]);
    if (count > 0) {
      setStatus("Build order added!");
      setName("");
      setVs("");
      setDescription("");
      setNote("");
      setKeyTimingMinute("");
      setKeyTimingNote("");
      setSteps([{ time: "0:00", instruction: "", food: "" }]);
      setSkills([]);
    } else {
      setStatus("Please fill in Name and at least one step with all fields.");
    }
    setTimeout(() => setStatus(""), 4000);
  }

  return (
    <section className="section-card build-order-input-section">
      <h4 className="skill-order-title">Add Build Order</h4>

      {/* ── Form fields in two-column grid ── */}
      <div className="boi-grid">
        <div className="boi-field">
          <span className="boi-label">Name</span>
          <EscEditBox value={name} placeholder="Build order name" onChange={setName} />
        </div>
        <div className="boi-field">
          <span className="boi-label">Race</span>
          <GlueDropdown
            options={RACES}
            value={race}
            onChange={(v) => setRace(v as Race)}
            label={(v) => RACE_LABELS[v as Race] ?? v}
          />
        </div>
        <div className="boi-field">
          <span className="boi-label">vs</span>
          <EscEditBox value={vs} placeholder="e.g. Human, all" onChange={setVs} />
        </div>
        <div className="boi-field">
          <span className="boi-label">Difficulty</span>
          <GlueDropdown
            options={DIFFICULTIES}
            value={difficulty}
            onChange={(v) => setDifficulty(v as Difficulty)}
          />
        </div>
        <div className="boi-field boi-field--wide">
          <span className="boi-label">Description</span>
          <EscEditBox value={description} placeholder="Short description" onChange={setDescription} />
        </div>
        <div className="boi-field boi-field--wide">
          <span className="boi-label">Note</span>
          <EscEditBox value={note} placeholder="Optional note" onChange={setNote} />
        </div>
        <div className="boi-field">
          <span className="boi-label">Key Timing (min)</span>
          <EscEditBox value={keyTimingMinute} placeholder="e.g. 3" onChange={setKeyTimingMinute} />
        </div>
        <div className="boi-field">
          <span className="boi-label">Key Timing Note</span>
          <EscEditBox value={keyTimingNote} placeholder="Timing note" onChange={setKeyTimingNote} />
        </div>
      </div>

      {/* ── Steps ── */}
      <div className="boi-table-section">
        <h5 className="boi-table-title">Steps</h5>
        <div className="boi-table-wrap">
          <table className="build-steps-table boi-table">
            <thead>
              <tr>
                <th className="boi-col-num">#</th>
                <th className="boi-col-time">Time</th>
                <th>Instruction</th>
                <th className="boi-col-food">Food</th>
                <th className="boi-col-action"></th>
              </tr>
            </thead>
            <tbody>
              {steps.map((step, i) => (
                <tr key={i}>
                  <td className="build-step-order">{i + 1}</td>
                  <td>
                    <EscEditBox
                      value={step.time}
                      placeholder="0:00"
                      onChange={(v) => updateStep(i, "time", v)}
                    />
                  </td>
                  <td>
                    <EscEditBox
                      value={step.instruction}
                      placeholder="Instruction"
                      onChange={(v) => updateStep(i, "instruction", v)}
                    />
                  </td>
                  <td>
                    <EscEditBox
                      value={step.food}
                      placeholder="5/10"
                      onChange={(v) => updateStep(i, "food", v)}
                    />
