 8→const BG_BLP = "/borders/esc/editbox-background.blp";
 9→const BORDER_BLP = "/borders/esc/editbox-border.blp";
10→const CORNER_RATIO = 0.0125 / 0.04;
11→const FILL_INSET_PX = 2;
12→const FILL_CORNER_CAP_PX = 8;
13→
14→interface Props {
15→  value: string;
16→  placeholder?: string;
17→  onChange: (value: string) => void;
