20→export default function EscEditBox({ value, placeholder, onChange }: Props) {
21→  const canvasRef = useRef<HTMLCanvasElement>(null);
22→
23→  useEffect(() => {
24→    const canvas = canvasRef.current;
25→    if (!canvas) return;
26→    let cancelled = false;
27→
28→    void Promise.all([
29→      loadBlpDataUrl(BG_BLP).then(loadDataUrlImage),
30→      loadBlpDataUrl(BORDER_BLP).then(loadDataUrlImage),
31→    ])
32→      .then(([bgImg, borderImg]) => {
33→        if (cancelled) return;
34→        const h = canvas.clientHeight || 1;
35→        drawTemplateNineSliceToCanvas(canvas, bgImg, borderImg, {
36→          cornerPx: h * CORNER_RATIO,
37→          insetPx: FILL_INSET_PX,
38→          tileBackground: true,
39→          tileHorizontalEdges: true,
40→          opaqueBaseFill: "#000",
41→          fillCornerMaxPx: FILL_CORNER_CAP_PX,
42→        });
43→      })
44→      .catch((err) => console.error(err));
45→
46→    return () => {
47→      cancelled = true;
48→    };
49→  }, []);
50→
51→  return (
52→    <label className="wc3-editbox wc3-editbox--esc">
53→      <canvas ref={canvasRef} className="wc3-editbox-canvas" />
54→      <input
55→        type="text"
56→        value={value}
57→        placeholder={placeholder}
58→        onChange={(e) => onChange(e.currentTarget.value)}
59→      />
60→    </label>
61→  );
62→}
