 92→export default function BuildOrderInputSection() {
 93→  const [name, setName] = useState("");
 94→  const [race, setRace] = useState<Race>("Human");
 95→  const [vs, setVs] = useState("");
 96→  const [difficulty, setDifficulty] = useState<Difficulty>("Beginner");
 97→  const [description, setDescription] = useState("");
 98→  const [note, setNote] = useState("");
 99→  const [keyTimingMinute, setKeyTimingMinute] = useState("");
100→  const [keyTimingNote, setKeyTimingNote] = useState("");
101→  const [steps, setSteps] = useState<StepRow[]>([
102→    { time: "0:00", instruction: "", food: "" },
103→  ]);
104→  const [skills, setSkills] = useState<SkillRow[]>([]);
105→  const [status, setStatus] = useState("");
106→
107→  function updateStep(index: number, field: keyof StepRow, value: string) {
108→    setSteps((prev) =>
109→      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
110→    );
111→  }
112→
113→  function addStep() {
114→    setSteps((prev) => [...prev, { time: "", instruction: "", food: "" }]);
115→  }
116→
117→  function removeStep(index: number) {
118→    setSteps((prev) => prev.filter((_, i) => i !== index));
119→  }
120→
121→  function updateSkill(index: number, field: keyof SkillRow, value: string) {
122→    setSkills((prev) =>
123→      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
124→    );
125→  }
126→
127→  function addSkill() {
128→    setSkills((prev) => [
129→      ...prev,
130→      { level: String(prev.length + 1), skill: "" },
131→    ]);
132→  }
133→
134→  function removeSkill(index: number) {
135→    setSkills((prev) => prev.filter((_, i) => i !== index));
136→  }
137→
138→  function handleSubmit() {
139→    const keyTimingMin = Number(keyTimingMinute);
140→    const build = {
141→      name,
142→      race,
143→      vs: vs || undefined,
144→      difficulty,
145→      description,
146→      note: note || undefined,
147→      keyTiming:
148→        keyTimingMinute && keyTimingNote
149→          ? { minute: keyTimingMin, note: keyTimingNote }
150→          : undefined,
151→      steps: steps.map((s, i) => ({
152→        order: i + 1,
153→        time: s.time,
154→        instruction: s.instruction,
155→        food: s.food,
156→      })),
157→      skillOrder:
158→        skills.length > 0
159→          ? skills.map((s) => ({
160→              level: Number(s.level),
161→              skill: s.skill,
162→              icon: skillToIconPath(s.skill),
163→            }))
164→          : undefined,
165→    };
166→
167→    const count = importBuilds([build]);
168→    if (count > 0) {
169→      setStatus("Build order added!");
170→      setName("");
171→      setVs("");
172→      setDescription("");
173→      setNote("");
174→      setKeyTimingMinute("");
175→      setKeyTimingNote("");
176→      setSteps([{ time: "0:00", instruction: "", food: "" }]);
177→      setSkills([]);
178→    } else {
179→      setStatus("Please fill in Name and at least one step with all fields.");
180→    }
181→    setTimeout(() => setStatus(""), 4000);
182→  }
183→
184→  return (
185→    <section className="section-card build-order-input-section">
186→      <h4 className="skill-order-title">Add Build Order</h4>
187→
188→      {/* ── Form fields in two-column grid ── */}
189→      <div className="boi-grid">
190→        <div className="boi-field">
191→          <span className="boi-label">Name</span>
192→          <EscEditBox value={name} placeholder="Build order name" onChange={setName} />
193→        </div>
194→        <div className="boi-field">
195→          <span className="boi-label">Race</span>
196→          <GlueDropdown
197→            options={RACES}
198→            value={race}
199→            onChange={(v) => setRace(v as Race)}
200→            label={(v) => RACE_LABELS[v as Race] ?? v}
201→          />
202→        </div>
203→        <div className="boi-field">
204→          <span className="boi-label">vs</span>
