315→                  </td>
316→                  <td>
317→                    <GlueSmallButton onClick={() => removeSkill(i)}>
318→                      ✕
319→                    </GlueSmallButton>
320→                  </td>
321→                </tr>
322→              ))}
323→            </tbody>
324→          </table>
325→        </div>
326→        <GlueSmallButton onClick={addSkill}>+ Add Skill</GlueSmallButton>
327→      </div>
328→
329→      {/* ── Submit ── */}
330→      <div className="boi-submit">
331→        <GlueBorderedButton onClick={handleSubmit}>Add Build</GlueBorderedButton>
332→        {status && <span className="build-import-status">{status}</span>}
333→      </div>
334→    </section>
335→  );
336→}
