/* ── Build Order Input Section ─────────────────────────────── */
.build-order-input-section {
  margin-top: 0.75rem;
  padding: 1rem 1.25rem;
}

/* Two-column form grid */
.boi-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
