/* Command Card (Hotkey) Buttons */
@property --sweep {
  syntax: "<angle>";
  inherits: false;
  initial-value: 360deg;
}

.cmd-btn {
  position: relative;
  width: 48px;
  height: 48px;
  border: none;
  border-radius: 0;
  overflow: hidden;
  cursor: pointer;
  padding: 0;
  background: transparent;
  flex-shrink: 0;
  color: #f0d775;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

.cmd-btn--showcase {
  width: 64px;
  height: 64px;
}

.cmd-btn:focus-visible {
  outline: 1px solid #f0d775;
  outline-offset: 1px;
}

.cmd-btn:disabled {
  cursor: default;
}

.cmd-btn img {
  image-rendering: pixelated;
}

.cmd-btn-backdrop,
.cmd-btn-icon,
.cmd-btn-frame {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  pointer-events: none;
}

.cmd-btn-backdrop {
  z-index: 1;
}

.cmd-btn-icon {
  z-index: 2;
}

.cmd-btn-frame {
  z-index: 3;
}

.cmd-btn-highlight {
  position: absolute;
  inset: 0;
  background-size: 100% 100%;
  mix-blend-mode: screen;
  opacity: 0;
  transition: opacity 80ms linear;
  pointer-events: none;
  z-index: 4;
}

.cmd-btn:hover .cmd-btn-highlight,
.cmd-btn-highlight.cmd-btn-highlight--on {
  opacity: 1;
}

.cmd-btn--pressed img {
  filter: brightness(0.7);
}

.cmd-btn--pressed {
  transform: translate(1px, 1px);
}

.cmd-btn-hotkey {
  position: absolute;
  right: 2px;
  bottom: 2px;
  font-size: 0.62rem;
  font-weight: 700;
  line-height: 1;
  color: #f0d775;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
  user-select: none;
  z-index: 5;
}

@keyframes cooldown-sweep {
  from {
    --sweep: 360deg;
  }
  to {
    --sweep: 0deg;
  }
}

.cmd-btn-cooldown {
  position: absolute;
  inset: 0;
  background: conic-gradient(
    from 0deg,
    rgba(0, 0, 0, 0.75) var(--sweep),
    transparent var(--sweep)
  );
  animation: cooldown-sweep 8s linear infinite;
  pointer-events: none;
  z-index: 6;
}

.cmd-btn-no-resources {
  position: absolute;
  inset: 0;
  background: rgba(255, 40, 40, 0.35);
  pointer-events: none;
  z-index: 6;
}

.cmd-btn--no-resources .cmd-btn-hotkey {
  color: #ffb3b3;
}

.command-card-preview {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.command-card-grid {
  display: grid;
  grid-template-columns: repeat(4, 64px);
  grid-template-rows: repeat(3, 64px);
  gap: 8px;
  padding: 0;
}

.command-card-cell {
  width: 64px;
  height: 64px;
}

.command-card-cell .cmd-btn {
  width: 100%;
  height: 100%;
}

.command-card-cell .cmd-btn-hotkey {
  right: 3px;
  bottom: 3px;
  font-size: 0.78rem;
}

.cmd-btn-fallback-icon {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #dbe5ff;
  background: radial-gradient(
    circle at 35% 30%,
    #2f4f96 0%,
    #112342 60%,
    #090f1e 100%
  );
  font-size: 1.05rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  pointer-events: none;
  z-index: 2;
}

.cmd-btn-empty {
  cursor: default;
  background-color: #020308;
}

.cmd-btn--passive .cmd-btn-icon {
  filter: saturate(0.72) brightness(0.88);
}

.cmd-btn--levelup .cmd-btn-icon {
  filter: saturate(1.1) brightness(1.08);
}

.cmd-btn--levelup .cmd-btn-hotkey {
  color: #ffd843;
}

.unit-queue-preview {
