.skill-pick-icon {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  object-fit: cover;
}

.skill-pick-icon--placeholder {
  width: 100%;
  height: 100%;
  background: rgba(252, 211, 18, 0.06);
}

.skill-pick-name {
  font-size: 0.62rem;
  color: #c8b97a;
  text-align: center;
  line-height: 1.2;
  white-space: nowrap;
}

.skill-pick-connector {
  flex: 1;
  height: 1px;
  min-width: 8px;
  margin: 0 0.35rem;
  margin-top: 21px;
  background: linear-gradient(
    90deg,
    rgba(252, 211, 18, 0.4),
    rgba(252, 211, 18, 0.15)
  );
}

@media (max-width: 700px) {
  .build-card {
    grid-template-columns: 1fr;
  }

  .build-card-info {
    border-right: none;
    border-bottom: 1px solid rgba(252, 211, 18, 0.2);
  }
}

