// Effect: bnet editbox canvas
useEffect(() => {
  const canvas = bnetEditboxCanvasRef.current;
  const bgUrlVal = bnetInputBgUrl;
  const borderUrlVal = bnetInputBorderUrl;
  if (!canvas || !bgUrlVal || !borderUrlVal) return;
  let cancelled = false;

  void Promise.all([
    loadDataUrlImage(bgUrlVal),
    loadDataUrlImage(borderUrlVal),
  ])
    .then(([bgImg, borderImg]) => {
      if (cancelled) return;
      const h = canvas.clientHeight || 1;
      drawTemplateNineSliceToCanvas(canvas, bgImg, borderImg, {
        cornerPx: h * bnetControlCornerRatio,
        insetPx: h * bnetControlInsetRatio,
        tileBackground: true,
        tileHorizontalEdges: true,
        opaqueBaseFill: "#000",
      });
    })
    .catch((err) => console.error(err));

  return () => {
    cancelled = true;
  };
}, [bnetInputBgUrl, bnetInputBorderUrl, activePage]);

