      <div className="boi-group">
        <div className="boi-field">
          <span className="boi-label">Race</span>
          <GlueDropdown
            options={RACES}
            value={race}
            onChange={(v) => setRace(v as Race)}
            label={(v) => RACE_LABELS[v as Race] ?? v}
          />
        </div>
        <div className="boi-field">
          <span className="boi-label">vs</span>
          <GlueDropdown
            options={["Any" as const, ...RACES]}
            value={vs || ("Any" as string)}
            onChange={(v) => setVs(v === "Any" ? "" : v)}
            label={(v) => (v === "Any" ? "Any" : RACE_LABELS[v as Race] ?? v)}
          />
        </div>
        <div className="boi-field">
          <span className="boi-label">Difficulty</span>
          <GlueDropdown
            options={DIFFICULTIES}
            value={difficulty}
            onChange={(v) => setDifficulty(v as Difficulty)}
          />
        </div>
      </div>

      {/* ── Key Timing ── */}
      <div className="boi-group">
        <div className="boi-field">
          <span className="boi-label">Key Timing (min)</span>
          <EscEditBox value={keyTimingMinute} placeholder="e.g. 3" onChange={setKeyTimingMinute} />
        </div>
