      <div className="boi-group">
        <div className="boi-field">
          <span className="boi-label">Key Timing (min)</span>
          <EscEditBox value={keyTimingMinute} placeholder="e.g. 3" onChange={setKeyTimingMinute} />
        </div>
        <div className="boi-field">
          <span className="boi-label">Timing Note</span>
          <EscEditBox value={keyTimingNote} placeholder="Tier 2 should complete" onChange={setKeyTimingNote} />
        </div>
      </div>

      {/* ── Steps ── */}
      <div className="boi-table-section">
        <h5 className="boi-table-title">Steps</h5>
        <div className="boi-step-list">
          {steps.map((step, i) => (
            <div key={i} className="boi-step-row">
              <span className="boi-step-num">{i + 1}</span>
              <EscEditBox
                value={step.time}
                placeholder="0:00"
                onChange={(v) => updateStep(i, "time", v)}
              />
              <EscEditBox
                value={step.instruction}
                placeholder="Instruction"
                onChange={(v) => updateStep(i, "instruction", v)}
              />
              <EscEditBox
                value={step.food}
                placeholder="5/10"
                onChange={(v) => updateStep(i, "food", v)}
              />
              {steps.length > 1 && (
                <GlueSmallButton onClick={() => removeStep(i)}>
                  Remove
                </GlueSmallButton>
              )}
            </div>
          ))}
        </div>
        <GlueSmallButton onClick={addStep}>+ Add Step</GlueSmallButton>
      </div>

      {/* ── Skill Order ── */}
      <div className="boi-table-section">
        <h5 className="boi-table-title">Skill Order</h5>
        <div className="boi-step-list">
          {skills.map((skill, i) => (
            <div key={i} className="boi-step-row">
              <span className="boi-step-num">Lv{skill.level}</span>
              <EscEditBox
                value={skill.skill}
                placeholder="e.g. Storm Bolt"
                onChange={(v) => updateSkill(i, "skill", v)}
              />
              <GlueSmallButton onClick={() => removeSkill(i)}>
                Remove
              </GlueSmallButton>
            </div>
          ))}
        </div>
        <GlueSmallButton onClick={addSkill}>+ Add Skill</GlueSmallButton>
      </div>

      {/* ── Submit ── */}
      <div className="boi-submit">
        <GlueBorderedButton onClick={handleSubmit}>Add Build</GlueBorderedButton>
        {status && <span className="build-import-status boi-status">{status}</span>}
      </div>
    </section>
  );
}

