/* ── Build Order Input Section ─────────────────────────────── */
.boi-section {
  margin-top: 0.75rem;
  padding: 1rem 1.25rem;
}

.boi-group {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem 1.25rem;
  margin-bottom: 1rem;
  padding-bottom: 1rem;
  border-bottom: 1px solid rgba(88, 104, 158, 0.25);
}

.boi-group:last-of-type {
  border-bottom: none;
  padding-bottom: 0;
}

.boi-field {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

.boi-label {
  font-size: 0.68rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

/* Steps + skill order */
.boi-table-section {
  margin-bottom: 1.25rem;
}

.boi-table-title {
  margin: 0 0 0.6rem;
  font-size: 0.72rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: normal;
}

.boi-step-list {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  margin-bottom: 0.5rem;
}

.boi-step-row {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.5rem;
}

.boi-step-num {
  min-width: 2rem;
  font-size: 0.78rem;
  color: var(--wc3-gold);
  text-align: center;
  font-variant-numeric: tabular-nums;
}

/* Submit row */
.boi-submit {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.boi-status {
  display: inline;
}

