/* ── Build Order Input Section ─────────────────────────────── */
.boi-section {
  margin-top: 0.75rem;
  padding: 1rem 1.25rem;
}

/* Form field groups — 3-column grid, fields at natural width */
.boi-group {
  display: grid;
  grid-template-columns: repeat(3, auto);
  justify-content: start;
  gap: 0.75rem 1.25rem;
  margin-bottom: 1rem;
  padding-bottom: 1rem;
  border-bottom: 1px solid rgba(88, 104, 158, 0.25);
}

.boi-group:last-of-type {
  border-bottom: none;
  padding-bottom: 0;
}

.boi-field {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

.boi-label {
  font-size: 0.68rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding-left: 2px;
}

/* Steps + skill order */
.boi-table-section {
  margin-bottom: 1.25rem;
}

.boi-table-title {
  margin: 0 0 0.6rem;
  font-size: 0.72rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: normal;
}

.boi-step-list {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  margin-bottom: 0.5rem;
}

/* Step row: number | time | instruction | food | action */
.boi-step-row {
  display: grid;
  grid-template-columns: 2.5rem 248px 248px 248px 146px;
  align-items: center;
  gap: 0.5rem;
}

/* Skill row: level | skill name | action */
.boi-skill-row {
  display: grid;
  grid-template-columns: 2.5rem 248px 146px;
  align-items: center;
  gap: 0.5rem;
}

.boi-step-num {
  font-size: 0.78rem;
  color: var(--wc3-gold);
  text-align: center;
  font-variant-numeric: tabular-nums;
}

/* Keep remove buttons stable even when first row hides it */
.boi-step-row .glue-small-button,
.boi-skill-row .glue-small-button {
  justify-self: start;
}

/* Submit row */
.boi-submit {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.boi-status {
  display: inline;
}

@media (max-width: 960px) {
  .boi-group {
    grid-template-columns: repeat(2, auto);
  }
  .boi-step-row {
    grid-template-columns: 2.5rem 1fr 1fr 1fr auto;
  }
  .boi-step-row .wc3-editbox,
  .boi-skill-row .wc3-editbox {
    width: 100%;
    min-width: 100px;
  }
  .boi-skill-row {
    grid-template-columns: 2.5rem 1fr auto;
  }
}

@media (max-width: 600px) {
  .boi-group {
    grid-template-columns: auto;
  }
}

