            <span className="tooltip-cost"><img src={props.goldIconUrl} alt="" /> 135</span>
            <span className="tooltip-cost"><img src={props.lumberIconUrl} alt="" /> 0</span>
            <span className="tooltip-cost"><img src={props.supplyIconUrl} alt="" /> 2</span>
          </div>
        </article>
      </div>
    </section>
  );
}

