@font-face {
  font-family: "Friz Quadrata";
  src: url("/fonts/FRIZQT__.TTF") format("truetype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

html,
body,
#root {
  margin: 0;
  width: 100%;
  height: 100%;
}

body {
  background: #08080f;
  color: #fff;
  overflow: hidden;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

:root {
  --card-bg: #111118;
  --card-border: #222233;
  --wc3-white: #ffffff;
  --wc3-gold: #fcd312;
  --wc3-dark-gold: #cca300;
  --wc3-game-cursor: auto;
}

body,
body * {
  cursor: var(--wc3-game-cursor) !important;
}

.viewport {
  position: absolute;
  inset: 0;
  overflow: auto;
  pointer-events: auto;
  padding: 24px 32px;
  padding-top: calc(4vw + 12px);
}

.viewport::-webkit-scrollbar {
